import React, { useState, useEffect, useCallback, useRef } from 'react';
import axios from 'axios';
import Cookies from 'js-cookie';
import { NavLink, useNavigate } from 'react-router-dom';
import '../AdminPanel.css';

const API_BASE_URL = 'http://localhost:5000/api';

const UserManagement = () => {
    const [success, setSuccess] = useState('');
    const [error, setError] = useState('');
    const [users, setUsers] = useState([]);
    const [offset, setOffset] = useState(0);
    const [limit] = useState(10);
    const [hasMore, setHasMore] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [formData, setFormData] = useState({
        id: null,
        prefix: 'Mr',
        userName: '',
        phoneNumber: '',
        userEmail: '',
        dateOfBirth: ''
    });
    const [isEditing, setIsEditing] = useState(false);
    const [loading, setLoading] = useState(false);
    const modalRef = useRef(null);
    const [bootstrapLoaded, setBootstrapLoaded] = useState(false);
    const navigate = useNavigate();

    useEffect(() => {
        const checkBootstrap = () => {
            if (window.bootstrap && window.bootstrap.Modal) {
                setBootstrapLoaded(true);
            } else {
                setTimeout(checkBootstrap, 100);
            }
        };
        checkBootstrap();

        if (!window.bootstrap) {
            const script = document.createElement('script');
            script.src = 'https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js';
            script.async = true;
            script.onload = () => setBootstrapLoaded(true);
            document.body.appendChild(script);
        }
    }, []);

    const fetchUsers = useCallback(async () => {
        try {
            setLoading(true);
            const token = Cookies.get('adminToken');
            const params = { limit, offset };
            if (searchTerm) params.q = searchTerm;

            const response = await axios.get(`${API_BASE_URL}/users`, {
                headers: { Authorization: `Bearer ${token}` },
                params
            });

            if (response.data.status) {
                setUsers(response.data.data);
                setHasMore(response.data.data.length === limit);
            } else {
                setError('Failed to fetch users');
            }
        } catch (err) {
            setError('Error fetching users');
        } finally {
            setLoading(false);
        }
    }, [limit, offset, searchTerm]);

    useEffect(() => {
        const token = Cookies.get('adminToken');
        if (!token) {
            navigate('/');
        } else {
            fetchUsers();
        }
    }, [navigate, fetchUsers]);

    const handlePrevious = () => {
        if (offset > 0) setOffset(offset - limit);
    };

    const handleNext = () => {
        if (hasMore) setOffset(offset + limit);
    };

    const handleSearchChange = (e) => {
        setSearchTerm(e.target.value);
        setOffset(0);
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });
    };

    const resetForm = () => {
        setFormData({
            id: null,
            prefix: 'Mr',
            userName: '',
            phoneNumber: '',
            userEmail: '',
            dateOfBirth: ''
        });
        setIsEditing(false);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!formData.userName || !formData.phoneNumber || !formData.userEmail || !formData.dateOfBirth) {
            setError('All fields are required');
            return;
        }

        try {
            const token = Cookies.get('adminToken');
            const url = isEditing
                ? `${API_BASE_URL}/users/${formData.id}`
                : `${API_BASE_URL}/users`;
            const method = isEditing ? 'put' : 'post';

            await axios[method](url, formData, {
                headers: { Authorization: `Bearer ${token}` }
            });

            setSuccess(isEditing ? 'User updated successfully' : 'User added successfully');
            setError('');
            resetForm();
            fetchUsers();

            if (isEditing && modalRef.current) {
                modalRef.current.hide();
            }

            setTimeout(() => setSuccess(''), 3000);
        } catch (err) {
            setError('Failed to save user');
        }
    };

    const handleEdit = (user) => {
        setFormData({
            id: user.userId,
            prefix: user.prefix,
            userName: user.userName,
            phoneNumber: user.phoneNumber,
            userEmail: user.userEmail,
            dateOfBirth: user.dateOfBirth.split('T')[0]
        });

        setIsEditing(true);

        const modalElement = document.getElementById('editUserModal');
        modalRef.current = new window.bootstrap.Modal(modalElement);
        modalRef.current.show();
    };

    const handleDelete = async (id) => {
        if (window.confirm('Are you sure you want to delete this user?')) {
            try {
                const token = Cookies.get('adminToken');
                await axios.delete(`${API_BASE_URL}/users/${id}`, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                setSuccess('User deleted successfully');
                fetchUsers();
                setTimeout(() => setSuccess(''), 2000);
            } catch {
                setError('Failed to delete user');
            }
        }
    };

    return (
        <div className="container-fluid py-5 bg-light min-vh-100">
            <div className="d-flex justify-content-between align-items-center mb-4 px-3">
                <h2 className="fw-bold text-primary">User Management</h2>
            </div>

            {success && <div className="alert alert-success mx-3">{success}</div>}
            {error && <div className="alert alert-danger mx-3">{error}</div>}

            {/* Add User Form */}
            <div className="card shadow mx-3 mb-4">
                <div className="card-body">
                    <h4 className="mb-3">Add New User</h4>
                    <form onSubmit={handleSubmit}>
                        <div className="row g-3">
                            <div className="col-md-2">
                                <select name="prefix" className="form-select" value={formData.prefix} onChange={handleInputChange}>
                                    <option value="Mr">Mr</option>
                                    <option value="Mrs">Mrs</option>
                                    <option value="Miss">Miss</option>
                                </select>
                            </div>
                            <div className="col-md-4">
                                <input type="text" name="userName" className="form-control" placeholder="Name"
                                    value={formData.userName} onChange={handleInputChange} required />
                            </div>
                            <div className="col-md-3">
                                <input type="text" name="phoneNumber" className="form-control" placeholder="Phone"
                                    value={formData.phoneNumber} onChange={handleInputChange} required />
                            </div>
                            <div className="col-md-3">
                                <input type="email" name="userEmail" className="form-control" placeholder="Email"
                                    value={formData.userEmail} onChange={handleInputChange} required />
                            </div>
                            <div className="col-md-3">
                                <input type="date" name="dateOfBirth" className="form-control"
                                    value={formData.dateOfBirth} onChange={handleInputChange} required />
                            </div>
                            <div className="col-md-9">
                                <button type="submit" className="btn btn-primary w-100">Add User</button>
                            </div>
                        </div>
                    </form>
                </div>
            </div>

            {/* User Table */}
            <div className="card shadow mx-3">
                <div className="card-body">
                    <div className="table-responsive">
                        <table className="table table-bordered table-striped">
                            <thead className="table-dark">
                                <tr>
                                    <th>ID</th>
                                    <th>Prefix</th>
                                    <th>Name</th>
                                    <th>Phone</th>
                                    <th>Email</th>
                                    <th>DOB</th>
                                    <th>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {users.map((user) => (
                                    <tr key={user.userId}>
                                        <td>{user.userId}</td>
                                        <td>{user.prefix}</td>
                                        <td>{user.userName}</td>
                                        <td>{user.phoneNumber}</td>
                                        <td>{user.userEmail}</td>
                                        <td>{new Date(user.dateOfBirth).toLocaleDateString()}</td>
                                        <td>
                                            <button className="btn btn-warning btn-sm me-2"
                                                onClick={() => handleEdit(user)}>
                                                Edit
                                            </button>
                                            <button className="btn btn-danger btn-sm"
                                                onClick={() => handleDelete(user.userId)}>
                                                Delete
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>

            {/* Edit Modal */}
            <div className="modal fade" id="editUserModal" tabIndex="-1">
                <div className="modal-dialog modal-xl modal-dialog-centered">
                    <div className="modal-content p-4">
                        <h4 className="mb-3">Edit User</h4>
                        <form onSubmit={handleSubmit}>
                            <div className="row g-3">
                                <div className="col-md-2">
                                    <select name="prefix" className="form-select"
                                        value={formData.prefix} onChange={handleInputChange}>
                                        <option value="Mr">Mr</option>
                                        <option value="Mrs">Mrs</option>
                                        <option value="Miss">Miss</option>
                                    </select>
                                </div>
                                <div className="col-md-4">
                                    <input type="text" name="userName" className="form-control"
                                        value={formData.userName} onChange={handleInputChange} required />
                                </div>
                                <div className="col-md-3">
                                    <input type="text" name="phoneNumber" className="form-control"
                                        value={formData.phoneNumber} onChange={handleInputChange} required />
                                </div>
                                <div className="col-md-3">
                                    <input type="email" name="userEmail" className="form-control"
                                        value={formData.userEmail} onChange={handleInputChange} required />
                                </div>
                                <div className="col-md-3">
                                    <input type="date" name="dateOfBirth" className="form-control"
                                        value={formData.dateOfBirth} onChange={handleInputChange} required />
                                </div>
                                <div className="col-12 text-end">
                                    <button type="button" className="btn btn-secondary me-2"
                                        data-bs-dismiss="modal">
                                        Cancel
                                    </button>
                                    <button type="submit" className="btn btn-primary">
                                        Update User
                                    </button>
                                </div>
                            </div>
                        </form>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default UserManagement;
